const POD_ID_WORD_COUNT = 3;

const toPodIdWord = (word: string) => `${word.charAt(0).toUpperCase()}${word.slice(1)}`;

const toPodId = (indexes: Iterable<number>) => {
  return Array.from(indexes).map(index => toPodIdWord(POD_ID_WORDS[index])).join('');
};

export function generateRandomPodId(): string {
  const indexes = new Set<number>();
  while (indexes.size < POD_ID_WORD_COUNT) {
    indexes.add(randomInt(POD_ID_WORDS.length));
  }

  return toPodId(indexes);
}

export function generateDeterministicPodId(seed: string): string {
  const hash = createHash('sha256').update(seed).digest();
  const indexes = new Set<number>();

  for (let offset = 0; indexes.size < POD_ID_WORD_COUNT; offset += 4) {
    const hashOffset = offset % (hash.length - 4);
    let index = hash.readUInt32BE(hashOffset) % POD_ID_WORDS.length;
    while (indexes.has(index)) {
      index = (index + 1) % POD_ID_WORDS.length;
    }
    indexes.add(index);
  }

  return toPodId(indexes);
}
